const express = require('express');
const multer = require('multer');
const path = require('path');
const exphbs = require('express-handlebars');
const upload = multer({ dest: 'uploads/' });
const fs = require('fs');

const app = express();
const port = process.env.PORT || 3000;

app.use(express.urlencoded({ extended: true }));

app.use(express.static('public')); // needed for css and js files


// handlebars
const hbs = exphbs.create();
app.engine('handlebars', hbs.engine);
app.set('view engine', 'handlebars');
app.set(express.static(__dirname + "/views"));

app.get("/", function (req, res) {
  res.render('home');
});

const base64 = "";

app.post("/upload", (req, res) => {
  // YYYY-MM-DD_HH:MM.jpg
  const date = new Date();
  const iso = date.toISOString().substr(0, 10);
  console.log(iso);
  fs.writeFile(__dirname + `/uploads/${iso}.png`, base64, 'base64', function(err) {
  console.log(err);
});
  res.status(201).send('ok');
});
